const body = $input.first().json.body || $input.first().json;
const text = (body.text || '').trim();
const chatId = String(body.chatId || '7713811206');

if (!text) {
  return [{ json: { route: 'error', error: 'text is required', chatId } }];
}

const lower = text.toLowerCase();

const SERVER_PATTERNS = [
  { route: 'task', keywords: ['\uBA54\uBAA8','\uB4F1\uB85D','\uCD94\uAC00','\uD560 \uC77C','todo'], webhook: 'flora-task-create' },
  { route: 'data', keywords: ['\uB9E4\uCD9C','\uACE0\uAC1D','\uD30C\uD2B8\uB108','\uCE94\uD398\uC778','\uC138\uADF8\uBA3C\uD2B8'], webhook: 'flora-biz-data' },
  { route: 'approve', keywords: ['\uC2B9\uC778','\uBC18\uB824','\uBCF4\uB958'], webhook: null },
];

const DEV_PATTERNS = [
  { route: 'prd', keywords: ['\uAE30\uD68D\uC548','PRD','\uC0C1\uC138\uD398\uC774\uC9C0 \uAE30\uD68D'], webhook: 'flora-prd-trigger' },
  { route: 'team', keywords: ['\uD300\uBBF8\uD305','\uC804\uB7B5 \uBD84\uC11D','\uB2E4\uAD00\uC810'], webhook: 'flora-team-meeting' },
  { route: 'dev', keywords: ['\uAC1C\uBC1C','\uC218\uC815','\uBC84\uADF8','\uD14C\uC2A4\uD2B8','\uAD6C\uD604'], webhook: 'flora-dev-dispatch' },
];

for (const p of SERVER_PATTERNS) {
  for (const kw of p.keywords) {
    if (lower.includes(kw.toLowerCase())) {
      return [{ json: { route: p.route, webhook: p.webhook, text, chatId, needsMac: false } }];
    }
  }
}

for (const p of DEV_PATTERNS) {
  for (const kw of p.keywords) {
    if (lower.includes(kw.toLowerCase())) {
      return [{ json: { route: p.route, webhook: p.webhook, text, chatId, needsMac: true } }];
    }
  }
}

return [{ json: { route: 'general', webhook: 'flora-specialist', text, chatId, needsMac: false } }];
